mapper.select:
select sum(sbpi.payable_amount) as payable_amount, sum(sbpi.amount_pre_tax) as amount_pre_tax, sum(sbpi.deduct_income_tax) as deduct_income_tax, sum(sbpi.amount_after_tax) as amount_after_tax from swm_bonus_payment_interface sbpi where sbpi.data_status = 'T'
and sbpi.work_card in (
right(replicate('0',6) + convert(varchar(6),#{item}),6)
)
and sbpi.group_id in (
#{groupId}
)
